---立绘特写播放动作
---@class LUISpineSpCtrl
local LUISpineSpCtrl = LxClass("LUISpineSpCtrl", nil)

--- Spine
LUISpineSpCtrl.TYPE_SPINE = 1

--- LUIHeroObject
LUISpineSpCtrl.TYPE_HEROOBJ = 2



local Tweening = DG.Tweening
local TweeningEaseMap =
{
    [1] =	  Tweening.Ease.Linear,
    [2] =	  Tweening.Ease.InSine,
    [3] =     Tweening.Ease.OutSine,
    [4] =     Tweening.Ease.InOutSine,
    [5] =     Tweening.Ease.InQuad,
    [6] =     Tweening.Ease.OutQuad,
    [7] =     Tweening.Ease.InOutQuad,
    [8] =     Tweening.Ease.InCubic,
    [9] =     Tweening.Ease.OutCubic,
    [10] =    Tweening.Ease.InOutCubic,
    [11] =    Tweening.Ease.InQuart,
    [12] =    Tweening.Ease.OutQuart,
    [13] =    Tweening.Ease.InOutQuart,
    [14] =    Tweening.Ease.InQuint,
    [15] =    Tweening.Ease.OutQuint,
    [16] =    Tweening.Ease.InOutQuint,
    [17] =    Tweening.Ease.InExpo,
    [18] =    Tweening.Ease.OutExpo,
    [19] =    Tweening.Ease.InOutExpo,
    [20] =    Tweening.Ease.InCirc,
    [21] =    Tweening.Ease.OutCirc,
    [22] =    Tweening.Ease.InOutCirc,
    [23] =    Tweening.Ease.InElastic,
    [24] =    Tweening.Ease.OutElastic,
    [25] =    Tweening.Ease.InOutElastic,
    [26] =    Tweening.Ease.InBack,
    [27] =    Tweening.Ease.OutBack,
    [28] =    Tweening.Ease.InOutBack,
    [29] =    Tweening.Ease.InBounce,
    [30] =    Tweening.Ease.OutBounce,
    [31] =    Tweening.Ease.InOutBounce,
    [32] =    Tweening.Ease.Flash,
    [33] =    Tweening.Ease.InFlash,
    [34] =    Tweening.Ease.OutFlash,
    [35] =    Tweening.Ease.InOutFlash,
}

function LUISpineSpCtrl:LUISpineSpCtrl()
    self._type = nil
end

function LUISpineSpCtrl:Destroy()
    if self._isDestroy then return end

    self:StopPlayTween()
    table.removeall(self)
    self._isDestroy = true
end

function LUISpineSpCtrl:Reset()
    self:ResetPlayPos()
    self._playData = nil
end

function LUISpineSpCtrl:ResetSpineAni()
    if not self._playData then return end
    local data = self._playData
    local type = data.type
    if type == LUISpineSpCtrl.TYPE_SPINE then
        ---@type LDisplaySpine
        local spine = data.spine
        if spine then
            spine:PlayAnimationSolid("idle",true)
        end
    elseif type == LUISpineSpCtrl.TYPE_HEROOBJ then
        ---@type LUIHeroObject
        local uiHeroObj = data.uiHeroObj
        if uiHeroObj then
            uiHeroObj:PlayIdleAni()
        end
    end
end

function LUISpineSpCtrl:ResetUI()
    self:StopPlayTween()
    self:ResetSpineAni()
    self:Reset()
end

function LUISpineSpCtrl:ResetPlayPos()
    if not self._playData then return end
    local data = self._playData

    local trans
    local bgTrans
    local hdTrans
    local type = data.type
    if type == LUISpineSpCtrl.TYPE_SPINE then
        trans = data.trans
        bgTrans = data.bgTrans
    elseif type == LUISpineSpCtrl.TYPE_HEROOBJ then
        ---@type LUIHeroObject
        local uiHeroObj = data.uiHeroObj
        if uiHeroObj then
            trans = uiHeroObj:GetParentTrans()
            bgTrans = uiHeroObj:GetParentBgTrans()
            hdTrans = uiHeroObj:GetParentHdTrans()
        end
    end


    if trans then
        trans.localScale = Vector3.one
        trans.anchoredPosition = data.initPos or Vector2.zero
    end

    if bgTrans then
        bgTrans.localScale = Vector3.one
        bgTrans.anchoredPosition = data.initPos or Vector2.zero
    end

    if hdTrans then
        hdTrans.localScale = Vector3.one
        hdTrans.anchoredPosition = data.initPos or Vector2.zero
    end
end

function LUISpineSpCtrl:StartPlayTween(data)
    self:StopPlayTween()

    local ref = GameTable.AutoCloseUpRef[data.closeUpRefId]
    if not ref then return end

    self._type = data.type or LUISpineSpCtrl.TYPE_SPINE

    self._refData = ref
    self._playData = data
    local seqTween = YXTween.TweenSequenceIns()
    self._playSeqTween = seqTween
    self:StepPlaySeqTween(seqTween, data)
    seqTween:OnComplete(function()
        self._playSeqTween = nil
        if data.cb ~= nil then
            data.cb(self, data)
        end
    end)
    seqTween:PlayForward()
end

local _actionHeader = {
    scale=1, scaleTime = 2, scaleEase = 3,
    initPosX = 4, initPosY = 5, movePosX = 6, movePosY = 7,
    moveTime = 8, moveEase = 9,spinePlaySpeed = 10
}

local _closeupDataHeader = {
    id = 1,
    ani = 2,
    actionList = 3
}

function LUISpineSpCtrl:StepPlaySeqTween(seqTween, data)
    local trans
    local bgTrans
    local hdTrans
    local type = data.type

    local ref = self._refData
    local action = ref[_closeupDataHeader.ani]

    ---@type LDisplaySpine
    local spine = nil

    ---@type LUIHeroObject
    local uiHeroObj = nil

    local actionTime
    if type == LUISpineSpCtrl.TYPE_SPINE then
        trans = data.trans
        bgTrans = data.bgTrans
        spine = data.spine
        spine:SetAnimationCompleteFunc(function(ani)
            if ani == action then
                spine:PlayAnimation(0, "idle", true)
            end
        end)
        spine:PlayAnimation(0,action,false)
        actionTime = LxResPathUtil.GetSpineAniTime(spine:GetSpineName(), action, 10)
    elseif type == LUISpineSpCtrl.TYPE_HEROOBJ then
        ---@type LUIHeroObject
        uiHeroObj = data.uiHeroObj
        if uiHeroObj then
            trans = uiHeroObj:GetParentTrans()
            bgTrans = uiHeroObj:GetParentBgTrans()
            hdTrans = uiHeroObj:GetParentHdTrans()
            uiHeroObj:PlayAni(action,false)
            actionTime = LxResPathUtil.GetSpineAniTime(uiHeroObj:GetSpineName(), action, 10)
        end
    end

    if not bgTrans then
        bgTrans = data.bgImgTrans
    end


    local actionList = ref[_closeupDataHeader.actionList]
    if #actionList and #actionList > 0 then
        local scaleSeq = YXTween.TweenSequenceIns()
        local moveSeq = YXTween.TweenSequenceIns()
        local playSpeedSeq = YXTween.TweenSequenceIns()
        local timePos = 0
        for k,v in ipairs(actionList) do
            local scale = v[_actionHeader.scale]
            local scaleTime = v[_actionHeader.scaleTime]
            local scaleEase = v[_actionHeader.scaleEase]
            local ix = -v[_actionHeader.initPosX] * 50
            local iy = -v[_actionHeader.initPosY] * 50
            local ex = -v[_actionHeader.movePosX] * 50
            local ey = -v[_actionHeader.movePosY] * 50
            local moveTime = v[_actionHeader.moveTime]
            local moveEase = v[_actionHeader.moveEase]
            local maxTime = math.max(scaleTime, moveTime)

            ---------------------- spine 播放速度 start
            local spinePlaySpeedFunc
            local spinePlaySpeed = v[_actionHeader.spinePlaySpeed]
            if type == LUISpineSpCtrl.TYPE_SPINE then
                if spine then
                    spinePlaySpeedFunc = function()
                        spine:SetAnimationTimeScale(spinePlaySpeed)
                    end
                end
            elseif type == LUISpineSpCtrl.TYPE_HEROOBJ then
                if uiHeroObj then
                    spinePlaySpeedFunc = function()
                        uiHeroObj:SetAnimationTimeScale(spinePlaySpeed)
                    end
                end
            end
            if spinePlaySpeedFunc then
                playSpeedSeq:InsertCallback(timePos,spinePlaySpeedFunc)
            end
            ---------------------- spine 播放速度 end


            local scaleTween = trans:DOScale(Vector3(scale, scale, scale), scaleTime)
            local scaleTween1 = bgTrans and bgTrans:DOScale(Vector3(scale, scale, scale), scaleTime) or nil

            local scaleHdTween
            if hdTrans then
                scaleHdTween = hdTrans:DOScale(Vector3(scale, scale, scale), scaleTime)
            end

            local ease = (scaleEase > 0) and TweeningEaseMap[scaleEase] or nil
            if ease then
                scaleTween:SetEase(ease)
                if scaleTween1 then scaleTween1:SetEase(ease) end

                if scaleHdTween then
                    scaleHdTween:SetEase(ease)
                end
            end
            scaleSeq:Append(scaleTween)
            if scaleTween1 then
                scaleSeq:Insert(timePos, scaleTween1)
            end

            if scaleHdTween then
                scaleSeq:Insert(timePos, scaleHdTween)
            end

            if scaleTime < maxTime then
                scaleSeq:AppendInterval(maxTime - scaleTime)
            end


            local moveTween = trans:DOAnchorPos(Vector2(ex, ey), moveTime)
            local moveTween1 = bgTrans and bgTrans:DOAnchorPos(Vector2(ex, ey), moveTime) or nil

            local moveHdTween
            if hdTrans then
                moveHdTween = hdTrans:DOAnchorPos(Vector2(ex, ey), moveTime)
            end

            ease = (moveEase > 0) and TweeningEaseMap[moveEase] or nil
            if ease then
                moveTween:SetEase(ease)
                if moveTween1 then
                    moveTween1:SetEase(ease)
                end

                if moveHdTween then
                    moveHdTween:SetEase(ease)
                end
            end

            moveSeq:AppendCallback(function()
                trans.anchoredPosition = Vector2(ix, iy)
                if bgTrans then bgTrans.anchoredPosition = Vector2(ix, iy) end

                if hdTrans then
                    hdTrans.anchoredPosition = Vector2(ix, iy)
                end
            end)
            moveSeq:Append(moveTween)
            if moveTween1 then
                moveSeq:Insert(timePos, moveTween1)
            end

            if moveHdTween then
                moveSeq:Insert(timePos,moveHdTween)
            end

            if moveTime < maxTime then
                moveSeq:AppendInterval(maxTime - moveTime)
            end


            timePos = timePos + maxTime
        end
        seqTween:Append(scaleSeq)
        seqTween:Insert(0, moveSeq)
        seqTween:Insert(0, playSpeedSeq)
    else
        if actionTime and actionTime > 0 then
            seqTween:AppendInterval(actionTime)
        end
    end
end

function LUISpineSpCtrl:StopPlayTween()
    if self._playSeqTween then
        self._playSeqTween:Kill(false)
        self._playSeqTween = nil
    end
end


return LUISpineSpCtrl